const WEIGHT_COLOR_BANDS = [
  ["#2563eb", "#06b6d4", "#22c55e", "#eab308", "#f97316", "#ef4444"],
  ["#7c3aed", "#3b82f6", "#14b8a6", "#84cc16", "#f59e0b", "#ec4899"],
  ["#0f766e", "#16a34a", "#ca8a04", "#ea580c", "#dc2626", "#9333ea"],
  ["#1d4ed8", "#0891b2", "#65a30d", "#d97706", "#db2777", "#7c3aed"],
] as const;

const getStableWeightColor = (weight: string) => {
  const normalized = normalizeWeightInput(weight).toUpperCase();

  if (!normalized || normalized === "BW" || normalized === "B") return "#9ca3af";

  const numericWeight = Number(normalized);
  if (Number.isFinite(numericWeight)) {
    const steppedIndex = Math.max(0, Math.round(numericWeight / 2.5));
    const bandSize = WEIGHT_COLOR_BANDS[0].length;
    const bandIndex = Math.floor(steppedIndex / bandSize) % WEIGHT_COLOR_BANDS.length;
    const colorIndex = steppedIndex % bandSize;
    return WEIGHT_COLOR_BANDS[bandIndex][colorIndex];
  }

  let hash = 0;
  for (let index = 0; index < normalized.length; index += 1) {
    hash = (hash * 31 + normalized.charCodeAt(index)) >>> 0;
  }

  const flatPalette = WEIGHT_COLOR_BANDS.flat();
  return flatPalette[hash % flatPalette.length];
};

const buildTrianglePath = (cx: number, cy: number, size: number) => {
  const half = size / 2;
  const height = size * 0.9;
  return `${cx},${cy - height / 2} ${cx - half},${cy + height / 2} ${cx + half},${cy + height / 2}`;
};

const escapeRegExp = (value: string) => value.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");

const formatTargetLabel = (target: string, metric: string) => {
  const trimmedTarget = String(target || "").trim();
  const trimmedMetric = String(metric || "").trim();

  if (!trimmedTarget) return "—";
  if (!trimmedMetric) return trimmedTarget;

  const metricPattern = new RegExp(`\\b${escapeRegExp(trimmedMetric)}\\b`, "i");
  return metricPattern.test(trimmedTarget) ? trimmedTarget : `${trimmedTarget} ${trimmedMetric}`.trim();
};

const formatDurationShort = (duration: string) => {
  const raw = String(duration || "").trim();
  if (!raw) return "";
  const number = extractFirstNumber(raw);
  const lower = raw.toLowerCase();

  if (lower.includes("hour") || lower.includes("hr")) {
    return number ? `${number} hr${number === "1" ? "" : "s"}` : raw;
  }

  if (lower.includes("minute") || lower.includes("min")) {
    return number ? `${number} min${number === "1" ? "" : "s"}` : raw;
  }

  return number ? `${number} min${number === "1" ? "" : "s"}` : raw;
};

const getBlockInteractionLabel = (block: Block) =>
  block.interactionMode === "alternating" || (block.type === "paired" && /alternate/i.test(block.notes || ""))
    ? "Alternating"
    : "";

const createPremiumField = (metric = "Sets", value = "", mode: ExerciseMetricMode = "memberInput"): ExerciseMetricField => ({
  id: uid(),
  metric,
  value,
  mode,
});

const getExercisePremiumFields = (exercise: Exercise, blockType?: BlockType): ExerciseMetricField[] => {
  if (exercise.premiumFields?.length) return exercise.premiumFields;

  const fallbackFields: ExerciseMetricField[] = [];
  const targetText = String(exercise.target || "").trim();
  const metricText = String(exercise.metric || "").trim();

  if (targetText || metricText) {
    fallbackFields.push({
      id: `${exercise.id}-legacy-target`,
      metric: metricText || (blockType === "single" ? "Performance" : "Sets"),
      value: targetText,
      mode: "target",
    });
  }

  fallbackFields.push({
    id: `${exercise.id}-legacy-input`,
    metric: blockType === "single" ? "Performance" : "Sets",
    value: "",
    mode: "memberInput",
  });

  return fallbackFields;
};

const getExerciseTargetFields = (exercise: Exercise, blockType?: BlockType) =>
  getExercisePremiumFields(exercise, blockType).filter((field) => field.mode === "target");

const getExerciseInputFields = (exercise: Exercise, blockType?: BlockType) =>
  getExercisePremiumFields(exercise, blockType).filter((field) => field.mode === "memberInput");

const formatPremiumFieldLabel = (field: ExerciseMetricField) =>
  [field.value, field.metric].filter(Boolean).join(" ").trim() || field.metric || "Target";

const normalizePremiumMetricKey = (metric: string) => String(metric || "").trim().toLowerCase();

const getSessionEntryValueForMetric = (entry: SessionExerciseInput | undefined, metric: string, blockType?: BlockType) => {
  if (!entry) return "";
  const key = normalizePremiumMetricKey(metric);
  if (key.includes("weight") || key === "lbs" || key === "load") return entry.weight || "";
  if (key.includes("set")) return entry.setsCompleted || "";
  if (key.includes("performance") || key.includes("output")) return entry.performance || "";
  return blockType === "single" ? entry.performance || "" : entry.setsCompleted || "";
};

const applySessionEntryValueForMetric = (entry: SessionExerciseInput, metric: string, value: string, blockType?: BlockType): SessionExerciseInput => {
  const key = normalizePremiumMetricKey(metric);
  if (key.includes("weight") || key === "lbs" || key === "load") return { ...entry, weight: normalizeWeightInput(value) };
  if (key.includes("set")) return { ...entry, setsCompleted: value };
  if (key.includes("performance") || key.includes("output")) return { ...entry, performance: value };
  return blockType === "single" ? { ...entry, performance: value } : { ...entry, setsCompleted: value };
};

const getPrimaryProgramOutcomeMetric = (exercise: Exercise, blockType?: BlockType) =>
  getExerciseInputFields(exercise, blockType)[0]?.metric || (blockType === "single" ? "Performance" : "Sets");


function ExerciseDot({
  cx,
  cy,
  payload,
  shape,
}: {
  cx?: number;
  cy?: number;
  payload?: GraphPoint | ChartPoint;
  shape: "circle" | "square" | "triangle" | "diamond";
}) {
  if (cx == null || cy == null || !payload) return null;

  const fill = getStableWeightColor(payload.weight);
  const stroke = fill;
  const size = shape === "diamond" ? 10 : 8;
  const strokeWidth = 1.5;

  if (shape === "square") {
    return <rect x={cx - size / 2} y={cy - size / 2} width={size} height={size} rx={2} fill={fill} stroke={stroke} strokeWidth={strokeWidth} vectorEffect="non-scaling-stroke" />;
  }

  if (shape === "triangle") {
    return <polygon points={buildTrianglePath(cx, cy, size)} fill={fill} stroke={stroke} strokeWidth={strokeWidth} vectorEffect="non-scaling-stroke" />;
  }

  if (shape === "diamond") {
    return <polygon points={`${cx},${cy - size / 2} ${cx + size / 2},${cy} ${cx},${cy + size / 2} ${cx - size / 2},${cy}`} fill={fill} stroke={stroke} strokeWidth={strokeWidth} vectorEffect="non-scaling-stroke" />;
  }

  return <circle cx={cx} cy={cy} r={size / 2} fill={fill} stroke={stroke} strokeWidth={strokeWidth} vectorEffect="non-scaling-stroke" />;
}

function GraphTooltip({
  active,
  payload,
}: {
  active?: boolean;
  payload?: Array<{ payload?: GraphPoint }>;
}) {
  if (!active || !payload?.length) return null;

  const point = payload[0]?.payload;
  if (!point) return null;

  const supportEntries = Object.entries(point.supportMetrics || {}).filter(([metric, value]) => {
    const key = metric.trim().toLowerCase();
    const text = String(value || "").trim();
    return Boolean(text) && !["weight", "sets", "set", "performance", "output"].includes(key);
  });
  const hasSupportTarget = supportEntries.some(([metric]) => metric.trim().toLowerCase() === "target");
  const fallbackTarget = String(point.target || "").trim();
  const flagLabels = (point.contextFlags || []).map(formatContextFlagLabel).filter(Boolean);

  return (
    <div className="rounded-xl border border-zinc-200 bg-white px-3 py-2 text-xs shadow-lg">
      <div className="font-semibold text-zinc-900">{point.exerciseName}</div>
      {flagLabels.length ? (
        <div className="mt-1 flex flex-wrap gap-1">
          {flagLabels.map((flag) => (
            <span key={flag} className="rounded-full bg-amber-100 px-2 py-0.5 text-[10px] font-bold uppercase tracking-wide text-amber-800">{flag}</span>
          ))}
        </div>
      ) : null}
      {fallbackTarget && !hasSupportTarget ? (
        <div className="mt-1 text-zinc-700">Target: <span className="font-semibold">{fallbackTarget}</span></div>
      ) : null}
      {supportEntries.map(([metric, value]) => (
        <div key={metric} className="mt-1 text-zinc-700">{metric}: <span className="font-semibold">{String(value).trim()}</span></div>
      ))}
      {point.scoringDirection === "lowerIsBetter" ? <div className="mt-1 text-zinc-500">Lower value is better.</div> : null}
    </div>
  );
}

function getSmartTooltipPosition(activePoint: ChartPoint | null, chartWidth: number) {
  const topCenter = { x: Math.max(72, chartWidth / 2 - 92), y: 8 };
  if (!activePoint) return topCenter;

  const hoveredX = Number(activePoint.chartX ?? activePoint.x ?? 0);
  if (hoveredX >= 3.5 && hoveredX <= 5.5) {
    return hoveredX < 4.5 ? { x: chartWidth - 214, y: 8 } : { x: 24, y: 8 };
  }

  return topCenter;
}


const PAIRED_SAME_Y_TOTAL_OFFSET = 0.26;

const getYAxisTickDy = (value: number) => {
  if (value === 7) return 2;
  if (value === 6) return 1;
  if (value === 1) return -1;
  return 0;
};

function GraphYAxisTick({
  x,
  y,
  payload,
}: {
  x?: number;
  y?: number;
  payload?: { value?: number | string };
}) {
  if (x == null || y == null || payload?.value == null) return null;

  const numericValue = Number(payload.value);
  const dy = Number.isFinite(numericValue) ? getYAxisTickDy(numericValue) : 0;

  return (
    <text x={x} y={y} dy={dy} textAnchor="end" fill="#71717a" fontSize={10}>
      {payload.value}
    </text>
  );
}


