// ===== SHARED ENGINE CORE =====
// Gym Tracker summaries use one route only:
// Tracker raw entries -> Tracker adapter signal -> Shared summary core -> rendered summary.
// Structured Program graphing and summary behavior remain on the existing mature engine.

type SharedEngineDomain = "program" | "tracker";
type SharedEngineConfidenceBand = "Low" | "Moderate" | "High" | "Strong Read";
type SharedSummaryTrendDirection = "favorable" | "stable" | "decline" | "unclear" | "completion";
type SharedSummaryLabel = "Baseline Building" | "Exceptional Growth" | "Moderate Growth" | "Stable Growth" | "Contextual Decline";

type SharedSummaryCoreInput = {
  domain: SharedEngineDomain;
  observedCount: number;
};

type SharedSummaryTextInput = {
  label: SharedSummaryLabel;
  confidenceBand: SharedEngineConfidenceBand;
  trendDirection: SharedSummaryTrendDirection;
  metricName?: string;
  contextLabel: string;
  entryCount: number;
  supportText?: string;
  interpretationMode?: "progression" | "consistency";
};

type SharedTrackerSummaryCoreInput = {
  exerciseName: string;
  contextLabel: string;
  entryCount: number;
  trendDirection: SharedSummaryTrendDirection;
  pointCount: number;
  deltaPercent: number;
  favorableStepCount: number;
  metricName?: string;
  hasCompletionOnly: boolean;
  supportText?: string;
};

type SharedTrackerSummaryOutput = Omit<TrackerSummaryInsight, "title">;

type SharedGraphCoreInput<TPoint> = {
  domain: SharedEngineDomain;
  points: TPoint[];
};

const SHARED_ENGINE_CORE = {
  graph: {
    version: "0.2-tracker-ready",
    normalizePoints<TPoint>({ points }: SharedGraphCoreInput<TPoint>): TPoint[] {
      return points;
    },
  },
  summary: {
    version: "1.0-tracker-single-route",
    resolveConfidenceBand({ domain, observedCount }: SharedSummaryCoreInput): SharedEngineConfidenceBand {
      if (domain === "tracker") {
        if (observedCount >= 13) return "Strong Read";
        if (observedCount >= 9) return "High";
        if (observedCount >= 5) return "Moderate";
        return "Low";
      }

      if (observedCount >= 6) return "High";
      if (observedCount >= 3) return "Moderate";
      return "Low";
    },
    resolveTrackerLabel({
      confidenceBand,
      trendDirection,
      hasCompletionOnly,
      pointCount,
      deltaPercent,
      favorableStepCount,
    }: {
      confidenceBand: SharedEngineConfidenceBand;
      trendDirection: SharedSummaryTrendDirection;
      hasCompletionOnly: boolean;
      pointCount: number;
      deltaPercent: number;
      favorableStepCount: number;
    }): SharedSummaryLabel {
      if (confidenceBand === "Low") return "Baseline Building";
      if (hasCompletionOnly) return "Stable Growth";
      if (trendDirection === "decline") return "Contextual Decline";
      if (trendDirection === "stable" || trendDirection === "unclear" || trendDirection === "completion") return "Stable Growth";

      const hasStrongSample = confidenceBand === "High" || confidenceBand === "Strong Read";
      const hasRepeatedForwardMovement = favorableStepCount >= 4 || favorableStepCount >= Math.max(3, pointCount - 2);
      const hasLargeMove = deltaPercent >= 0.35;

      if (trendDirection === "favorable" && hasStrongSample && hasRepeatedForwardMovement && hasLargeMove) {
        return "Exceptional Growth";
      }

      if (trendDirection === "favorable") return "Moderate Growth";

      return "Stable Growth";
    },
    composeTrackerBody({
      label,
      confidenceBand,
      trendDirection,
      metricName,
      interpretationMode,
    }: SharedSummaryTextInput): string {
      const metricPhrase = metricName ? `${metricName} performance` : "performance";

      if (label === "Baseline Building") {
        if (trendDirection === "favorable") {
          return "Your progression is favorable in the early stage of building your baseline.";
        }

        if (trendDirection === "stable") {
          return "Your output is holding steady while you build a baseline for this exercise.";
        }

        if (trendDirection === "decline") {
          return "Progress forms differently early on, and this pattern still needs more entries before calling a true decline.";
        }

        return "This is still early baseline-building data, so the tracker is watching for a clearer pattern before calling a trend.";
      }

      if (interpretationMode === "consistency") {
        return "This exercise is being read as completed-as-prescribed work, so the tracker is treating it as consistency rather than a performance trend.";
      }

      if (label === "Exceptional Growth") {
        return `Your ${metricPhrase} shows a standout upward pattern across the logged entries.`;
      }

      if (label === "Moderate Growth") {
        return `Your ${metricPhrase} is moving in a positive direction across the logged entries.`;
      }

      if (label === "Stable Growth") {
        return `Your ${metricPhrase} is holding a steady working range across the logged entries.`;
      }

      if (label === "Contextual Decline") {
        return `Your ${metricPhrase} is trending downward across the logged entries, so the tracker is flagging this as contextual decline.`;
      }

      return confidenceBand === "Low"
        ? "This is still early baseline-building data, so the tracker is watching for a clearer pattern before calling a trend."
        : "The tracker is watching for a clearer pattern before assigning a stronger interpretation.";
    },
    composeTrackerDetail({
      confidenceBand,
      contextLabel,
      entryCount,
      supportText,
      interpretationMode,
    }: SharedSummaryTextInput): string {
      const entryLabel = `entr${entryCount === 1 ? "y" : "ies"}`;
      const confidenceNote =
        confidenceBand === "Low"
          ? ` This is being treated as baseline-building because it only has ${entryCount} logged ${entryLabel}.`
          : "";

      const modeNote =
        interpretationMode === "consistency"
          ? " Consistency Check: this entry type is being read for adherence/completion rather than output progression."
          : "";

      return `${supportText || `This summary is based on ${entryCount} logged ${entryLabel} in ${contextLabel}.`}${confidenceNote}${modeNote}`;
    },
    buildTrackerSummaryOutput({
      contextLabel,
      entryCount,
      trendDirection,
      pointCount,
      deltaPercent,
      favorableStepCount,
      metricName,
      hasCompletionOnly,
      supportText,
    }: SharedTrackerSummaryCoreInput): SharedTrackerSummaryOutput {
      const reportAccuracy = this.resolveConfidenceBand({
        domain: "tracker",
        observedCount: entryCount,
      });
      const label = this.resolveTrackerLabel({
        confidenceBand: reportAccuracy,
        trendDirection,
        hasCompletionOnly,
        pointCount,
        deltaPercent,
        favorableStepCount,
      });
      const interpretationMode = hasCompletionOnly ? "consistency" : "progression";

      return {
        label,
        reportAccuracy,
        interpretationMode,
        body: this.composeTrackerBody({
          label,
          confidenceBand: reportAccuracy,
          trendDirection,
          metricName,
          contextLabel,
          entryCount,
          supportText,
          interpretationMode,
        }),
        detail: this.composeTrackerDetail({
          label,
          confidenceBand: reportAccuracy,
          trendDirection,
          metricName,
          contextLabel,
          entryCount,
          supportText,
          interpretationMode,
        }),
      };
    },
  },
} as const;


type TrackerSummaryVisualToken = {
  cardClass: string;
  chipClass: string;
  confidenceClass: string;
};

const getTrackerSummaryVisualToken = (label: string, confidenceBand: SharedEngineConfidenceBand): TrackerSummaryVisualToken => {
  const labelTokens: Record<string, { cardClass: string; chipClass: string }> = {
    "Baseline Building": {
      cardClass: "border-sky-200 bg-sky-50",
      chipClass: "bg-sky-100 text-sky-800",
    },
    "Exceptional Growth": {
      cardClass: "border-emerald-200 bg-emerald-50",
      chipClass: "bg-emerald-100 text-emerald-800",
    },
    "Moderate Growth": {
      cardClass: "border-teal-200 bg-teal-50",
      chipClass: "bg-teal-100 text-teal-800",
    },
    "Stable Growth": {
      cardClass: "border-slate-200 bg-slate-50",
      chipClass: "bg-slate-100 text-slate-700",
    },
    "Contextual Decline": {
      cardClass: "border-amber-200 bg-amber-50",
      chipClass: "bg-amber-100 text-amber-800",
    },
  };

  const confidenceTokens: Record<SharedEngineConfidenceBand, string> = {
    Low: "bg-white text-sky-700 border border-sky-200",
    Moderate: "bg-white text-teal-700 border border-teal-200",
    High: "bg-white text-emerald-700 border border-emerald-200",
    "Strong Read": "bg-white text-zinc-900 border border-zinc-300",
  };

  const labelToken = labelTokens[label] || labelTokens["Stable Growth"];
  return {
    cardClass: labelToken.cardClass,
    chipClass: labelToken.chipClass,
    confidenceClass: confidenceTokens[confidenceBand],
  };
};

