const MUSCLE_GROUP_ANATOMICAL_ORDER: MuscleGroup[] = ["Shoulders", "Chest", "Back", "Upper Body", "Biceps", "Triceps", "Forearm/Wrist", "Hand/Grip", "Core", "Full Body", "Lower Body", "Legs", "Cardio", "Other"];

