const getTodayInputDate = () => {
  const formatter = new Intl.DateTimeFormat("en-CA", {
    timeZone: "America/New_York",
    year: "numeric",
    month: "2-digit",
    day: "2-digit",
  });
  return formatter.format(new Date());
};

const normalizeTrackerExercise = (exercise: TrackerExercise): TrackerExercise => ({
  ...exercise,
  metrics: exercise.metrics || [],
  entries: exercise.entries || [],
});

const normalizeTrackerWorkout = (workout: TrackerWorkout): TrackerWorkout => {
  const exerciseSlots = (workout.exerciseSlots && workout.exerciseSlots.length
    ? workout.exerciseSlots
    : (workout.exerciseIds || []).map((exerciseId, index) => ({
        id: `legacy-${workout.id}-${exerciseId}-${index}`,
        exerciseId,
        createdAt: workout.createdAt || new Date().toISOString(),
        entries: [],
      }))
  ).map((slot) => ({ ...slot, entries: slot.entries || [] }));

  return {
    ...workout,
    exerciseIds: exerciseSlots.map((slot) => slot.exerciseId),
    exerciseSlots,
    circuitTarget: Math.max(1, Number(workout.circuitTarget || 1) || 1),
    currentCircuit: Math.max(1, Number(workout.currentCircuit || 1) || 1),
  };
};

const getTrackerWorkoutCircuitTarget = (workout: TrackerWorkout | null | undefined) =>
  Math.max(1, Number(workout?.circuitTarget || 1) || 1);

const getTrackerWorkoutCurrentCircuit = (workout: TrackerWorkout | null | undefined) => {
  const target = getTrackerWorkoutCircuitTarget(workout);
  const current = Math.max(1, Number(workout?.currentCircuit || 1) || 1);
  return Math.min(current, target);
};

const isTrackerEntryForCircuit = (entry: TrackerEntry, circuitIndex: number) =>
  Math.max(1, Number(entry.circuitIndex || 1) || 1) === circuitIndex;

const getTrackerContextKey = (exerciseId: string, workoutSlotId?: string | null) => workoutSlotId ? `workout-slot:${workoutSlotId}` : exerciseId;

const parseTrackerMetricValue = (value: string): TrackerParsedMetricValue => {
  const rawValue = String(value || "").trim();

  if (!rawValue) {
    return { rawValue: "", numericValue: null, unitLabel: "", isBodyweight: false };
  }

  if (/^(b|bw|body\s*weight)$/i.test(rawValue)) {
    return { rawValue: "BW", numericValue: null, unitLabel: "BW", isBodyweight: true };
  }

  const numericMatch = rawValue.match(/-?\d+(?:\.\d+)?/);
  const numericValue = numericMatch ? Number(numericMatch[0]) : null;
  const unitLabel = rawValue
    .replace(/-?\d+(?:\.\d+)?/, "")
    .replace(/[()/:,-]+/g, " ")
    .replace(/\s+/g, " ")
    .trim();

  return {
    rawValue,
    numericValue: numericValue !== null && Number.isFinite(numericValue) ? numericValue : null,
    unitLabel,
    isBodyweight: false,
  };
};

const normalizeTrackerMetricName = (metric: string) => String(metric || "").trim().toLowerCase();

const isTrackerMetricNamed = (metric: string, names: string[]) => {
  const normalized = normalizeTrackerMetricName(metric);
  return names.some((name) => normalized === name.toLowerCase());
};

const isCompletionMetric = (metric: string) => isTrackerMetricNamed(metric, ["completion", "completed", "done", "check", "checkmark"]);
const isWeightMetric = (metric: string) => isTrackerMetricNamed(metric, ["weight", "load"]);
const isTimeMetric = (metric: string) => isTrackerMetricNamed(metric, ["time"]);
const isDistanceMetric = (metric: string) => isTrackerMetricNamed(metric, ["distance", "miles", "yards"]);
const isSetMetric = (metric: string) => isTrackerMetricNamed(metric, ["sets", "set"]);
const isRepMetric = (metric: string) => isTrackerMetricNamed(metric, ["reps", "rep", "repetitions"]);

const isTruthyCompletionValue = (value: string) => /^(true|yes|y|done|complete|completed|check|checked|✓|✔|x|1)$/i.test(String(value || "").trim());

const getTrackerMetricList = (metrics: TrackerMetric[] | undefined, entries: TrackerEntry[]) => {
  const metricSet = new Set<string>();

  (metrics || []).forEach((metric) => {
    const trimmed = String(metric || "").trim();
    if (trimmed) metricSet.add(trimmed);
  });

  entries.forEach((entry) => {
    Object.keys(entry.values || {}).forEach((metric) => {
      const trimmed = String(metric || "").trim();
      if (trimmed) metricSet.add(trimmed);
    });
  });

  return Array.from(metricSet);
};

const getMetricNumericValues = (metric: string, entries: TrackerEntry[]) =>
  entries
    .map((entry) => parseTrackerMetricValue(entry.values?.[metric] || "").numericValue)
    .filter((value): value is number => value !== null);

const hasMeaningfulVariation = (values: number[]) => {
  if (values.length < 2) return false;
  const rounded = values.map((value) => Number(value.toFixed(4)));
  return new Set(rounded).size > 1;
};

const isConstantNumericMetric = (metric: string, entries: TrackerEntry[]) => {
  const values = getMetricNumericValues(metric, entries);
  return values.length >= 2 && !hasMeaningfulVariation(values);
};

const resolveTrackerMetricRoles = (metricList: string[], entries: TrackerEntry[]): Record<string, TrackerMetricRole> => {
  const roles: Record<string, TrackerMetricRole> = {};
  const hasSets = metricList.some(isSetMetric);
  const hasDistance = metricList.some(isDistanceMetric);
  const hasTime = metricList.some(isTimeMetric);

  metricList.forEach((metric) => {
    if (isCompletionMetric(metric)) roles[metric] = "completion";
    else if (isWeightMetric(metric)) roles[metric] = "color";
    else if (isSetMetric(metric)) roles[metric] = "measured";
    else if (isRepMetric(metric) && hasSets) roles[metric] = "support";
    else roles[metric] = "measured";
  });

  metricList.forEach((metric) => {
    if (roles[metric] !== "measured") return;
    if (isConstantNumericMetric(metric, entries)) roles[metric] = "support";
  });

  const distanceMetric = metricList.find(isDistanceMetric);
  const timeMetric = metricList.find(isTimeMetric);
  if (hasDistance && hasTime && distanceMetric && timeMetric) {
    const distanceValues = getMetricNumericValues(distanceMetric, entries);
    const timeValues = getMetricNumericValues(timeMetric, entries);
    const distanceVaries = hasMeaningfulVariation(distanceValues);
    const timeVaries = hasMeaningfulVariation(timeValues);

    if (distanceVaries && !timeVaries) {
      roles[distanceMetric] = "measured";
      roles[timeMetric] = "support";
    } else if (!distanceVaries && timeVaries) {
      roles[timeMetric] = "measured";
      roles[distanceMetric] = "support";
    } else if (distanceVaries && timeVaries) {
      roles[distanceMetric] = "measured";
      roles[timeMetric] = "measured";
    } else {
      roles[distanceMetric] = "support";
      roles[timeMetric] = "support";
    }
  }

  const anyMeasured = metricList.some((metric) => roles[metric] === "measured");
  if (!anyMeasured) {
    const fallback = metricList.find((metric) => roles[metric] !== "color" && roles[metric] !== "completion" && getMetricNumericValues(metric, entries).length > 0);
    if (fallback && !isConstantNumericMetric(fallback, entries)) roles[fallback] = "measured";
  }

  return roles;
};

const buildTrackerMetricGraphSeries = ({
  exerciseName,
  contextLabel,
  metrics,
  entries,
}: {
  exerciseName: string;
  contextLabel: string;
  metrics?: TrackerMetric[];
  entries?: TrackerEntry[];
}): TrackerMetricGraphSeries[] => {
  const sortedEntries = [...(entries || [])].sort(
    (a, b) => getSafeDateTime(a.entryDate || a.createdAt) - getSafeDateTime(b.entryDate || b.createdAt)
  );
  const metricList = getTrackerMetricList(metrics, sortedEntries);
  const metricRoles = resolveTrackerMetricRoles(metricList, sortedEntries);
  const supportMetrics = metricList.filter((metric) => metricRoles[metric] === "support");
  const colorMetric = metricList.find((metric) => metricRoles[metric] === "color");
  const completionMetric = metricList.find((metric) => metricRoles[metric] === "completion");
  const measuredMetrics = metricList.filter((metric) => metricRoles[metric] === "measured");
  const completionCount = completionMetric
    ? sortedEntries.filter((entry) => isTruthyCompletionValue(entry.values?.[completionMetric] || "")).length
    : 0;

  if (!measuredMetrics.length && completionMetric) {
    return [{
      metric: "Consistency Check",
      exerciseName,
      contextLabel,
      points: [],
      skippedValues: [],
      supportMetrics,
      colorMetric,
      completionOnly: completionCount > 0,
    }];
  }

  return measuredMetrics
    .map((metric) => {
      const points: TrackerMetricGraphPoint[] = [];
      const skippedValues: TrackerParsedMetricValue[] = [];

      sortedEntries.forEach((entry, index) => {
        const parsed = parseTrackerMetricValue(entry.values?.[metric] || "");

        if (parsed.numericValue === null) {
          if (parsed.rawValue) skippedValues.push(parsed);
          return;
        }

        const entryDate = entry.entryDate || entry.createdAt || "";
        const supportValues = Object.fromEntries(
          supportMetrics
            .map((supportMetric) => [supportMetric, String(entry.values?.[supportMetric] || "").trim()])
            .filter(([, value]) => Boolean(value))
        ) as Record<string, string>;
        const weightValue = colorMetric ? String(entry.values?.[colorMetric] || "").trim() : "";

        points.push({
          x: index + 1,
          xLabel: entryDate || `Entry ${index + 1}`,
          y: parsed.numericValue,
          entryId: entry.id,
          entryDate,
          createdAt: entry.createdAt,
          metric,
          rawValue: parsed.rawValue,
          unitLabel: parsed.unitLabel || metric,
          exerciseName,
          contextLabel,
          supportValues,
          weightValue,
        });
      });

      return { metric, exerciseName, contextLabel, points, skippedValues, supportMetrics, colorMetric };
    })
    .filter((series) => series.points.length || series.skippedValues.length);
};



const getTrackerSummaryEntryCount = (entries?: TrackerEntry[]) =>
  (entries || []).filter((entry) => Object.values(entry.values || {}).some((value) => String(value || "").trim())).length;

const getTrackerSeriesTrend = (series: TrackerMetricGraphSeries): {
  direction: SharedSummaryTrendDirection;
  pointCount: number;
  delta: number;
  deltaPercent: number;
  favorableStepCount: number;
  metricName: string;
} => {
  if (series.completionOnly) {
    return { direction: "completion", pointCount: 0, delta: 0, deltaPercent: 0, favorableStepCount: 0, metricName: series.metric };
  }

  const points = series.points || [];
  if (points.length < 2) {
    return { direction: "unclear", pointCount: points.length, delta: 0, deltaPercent: 0, favorableStepCount: 0, metricName: series.metric };
  }

  const first = points[0];
  const last = points[points.length - 1];
  const delta = last.y - first.y;
  const tolerance = Math.max(0.25, Math.abs(first.y || 0) * 0.03);
  const lowerIsBetter = isTimeMetric(series.metric);
  const deltaPercent = Math.abs(first.y || 0) > 0 ? Math.abs(delta) / Math.abs(first.y) : 0;

  let favorableStepCount = 0;
  for (let index = 1; index < points.length; index += 1) {
    const stepDelta = points[index].y - points[index - 1].y;
    if (Math.abs(stepDelta) <= tolerance) continue;
    if ((stepDelta > 0 && !lowerIsBetter) || (stepDelta < 0 && lowerIsBetter)) favorableStepCount += 1;
  }

  if (Math.abs(delta) <= tolerance) {
    return { direction: "stable", pointCount: points.length, delta, deltaPercent, favorableStepCount, metricName: series.metric };
  }

  const direction: SharedSummaryTrendDirection = delta > 0 || (delta < 0 && lowerIsBetter) ? "favorable" : "decline";

  return { direction, pointCount: points.length, delta, deltaPercent, favorableStepCount, metricName: series.metric };
};

const getTrackerSummaryContextText = (series: TrackerMetricGraphSeries[]) => {
  const weights = series.flatMap((item) => item.points.map((point) => String(point.weightValue || "").trim()).filter(Boolean));
  const uniqueWeights = Array.from(new Set(weights));
  const supportNames = Array.from(new Set(series.flatMap((item) => item.supportMetrics || [])));
  const contextParts: string[] = [];

  if (uniqueWeights.length === 1) {
    contextParts.push(`Weight context stayed at ${uniqueWeights[0]}.`);
  } else if (uniqueWeights.length > 1) {
    contextParts.push(`Weight context moved from ${uniqueWeights[0]} to ${uniqueWeights[uniqueWeights.length - 1]}.`);
  }

  if (supportNames.length) {
    contextParts.push(`Support/context tracked: ${supportNames.join(", ")}.`);
  }

  return contextParts.join(" ");
};

const buildTrackerSummaryInsight = ({
  exerciseName,
  contextLabel,
  metrics,
  entries,
  series,
}: {
  exerciseName: string;
  contextLabel: string;
  metrics?: TrackerMetric[];
  entries?: TrackerEntry[];
  series: TrackerMetricGraphSeries[];
}): TrackerSummaryInsight | null => {
  const entryCount = getTrackerSummaryEntryCount(entries);
  if (!entryCount) return null;

  const metricList = getTrackerMetricList(metrics, entries || []);
  const completionMetric = metricList.find(isCompletionMetric);
  const completionCount = completionMetric
    ? (entries || []).filter((entry) => isTruthyCompletionValue(entry.values?.[completionMetric] || "")).length
    : 0;
  const measuredSeries = series.filter((item) => !item.completionOnly && (item.points || []).length);
  const primaryTrend = measuredSeries.map(getTrackerSeriesTrend).find((trend) => trend.pointCount >= 2) || {
    direction: measuredSeries.length ? "unclear" : "completion",
    pointCount: measuredSeries[0]?.points?.length || 0,
    delta: 0,
    deltaPercent: 0,
    favorableStepCount: 0,
    metricName: measuredSeries[0]?.metric || "",
  };
  const supportText = getTrackerSummaryContextText(measuredSeries.length ? measuredSeries : series);
  const hasCompletionOnly = !measuredSeries.length && completionCount > 0;
  const sharedSummary = SHARED_ENGINE_CORE.summary.buildTrackerSummaryOutput({
    exerciseName,
    contextLabel,
    entryCount,
    trendDirection: primaryTrend.direction,
    pointCount: primaryTrend.pointCount,
    deltaPercent: primaryTrend.deltaPercent,
    favorableStepCount: primaryTrend.favorableStepCount,
    metricName: primaryTrend.metricName,
    hasCompletionOnly,
    supportText,
  });

  return {
    title: `${exerciseName} Summary`,
    ...sharedSummary,
  };
};

function TrackerSummaryCard({ insight }: { insight: TrackerSummaryInsight | null }) {
  if (!insight) return null;

  const visualToken = getTrackerSummaryVisualToken(insight.label, insight.reportAccuracy);

  return (
    <div className={`rounded-2xl border p-4 ${visualToken.cardClass}`}>
      <div className="flex items-start justify-between gap-3">
        <div>
          <div className="text-xs font-semibold uppercase tracking-[0.16em] text-zinc-500">Gym Tracker Summary</div>
          <div className="mt-1 text-base font-bold text-zinc-900">{insight.title}</div>
        </div>
        <div className={`rounded-full px-2 py-1 text-[11px] font-semibold ${visualToken.confidenceClass}`}>{insight.reportAccuracy} confidence</div>
      </div>
      <div className={`mt-3 inline-flex rounded-full px-3 py-1 text-xs font-bold ${visualToken.chipClass}`}>{insight.label}</div>
      <p className="mt-3 text-sm font-medium leading-6 text-zinc-800">{insight.body}</p>
      <p className="mt-2 text-sm leading-6 text-zinc-600">{insight.detail}</p>
    </div>
  );
}

const getProgramLength = (program: Program | null | undefined) => {
  const value = Number(program?.programLength);
  return Number.isFinite(value) && value > 0 ? value : DEFAULT_PROGRAM_LENGTH;
};

const getMemberPlanLabel = (plan: MemberPlan | undefined) => {
  if (plan === "basic") return "Basic Member";
  if (plan === "premium") return "Premium Member";
  return "Direct Member";
};

const normalizeMember = (member: Member): Member => ({
  ...member,
  memberPlan: member.memberPlan || "direct",
});

const normalizeProgram = (program: Program): Program => ({
  ...program,
  programLength: getProgramLength(program),
  inputMode: getProgramInputMode(program),
});

const getProgramPlannedSessionTotal = (program: Program | null | undefined) =>
  getProgramLength(program) * (program?.routines.length || 0);

const getProgramSessionCount = (sessions: SavedSession[], programId: string, memberId?: string | null) => {
  const sessionNumbers = new Set<string>();

  sessions.forEach((session) => {
    if (session.programId !== programId) return;
    if (memberId && session.memberId !== memberId) return;

    const normalized = String(session.sessionNumber || "").trim();
    sessionNumbers.add(normalized || session.id);
  });

  return sessionNumbers.size;
};

const getRoutineSessionCount = (sessions: SavedSession[], programId: string, routineId: string, memberId?: string | null) => {
  const sessionNumbers = new Set<string>();

  sessions.forEach((session) => {
    if (session.programId !== programId) return;
    if (session.routineId !== routineId) return;
    if (memberId && session.memberId !== memberId) return;

    const normalized = String(session.sessionNumber || "").trim();
    sessionNumbers.add(normalized || session.id);
  });

  return sessionNumbers.size;
};

