const normalizeWeightInput = (value: string) => {
  const trimmed = value.trim();

  if (!trimmed) return "";
  if (/^(b|bw|body\s*weight)$/i.test(trimmed)) return "BW";

  const numeric = extractFirstNumber(trimmed);
  return numeric || "";
};

