function TrackerTutorialModal({
  isOpen,
  stepIndex,
  onStepChange,
  onClose,
  onNeverShowAgain,
}: {
  isOpen: boolean;
  stepIndex: number;
  onStepChange: (index: number) => void;
  onClose: () => void;
  onNeverShowAgain: () => void;
}) {
  if (!isOpen) return null;

  const step = TRACKER_TUTORIAL_STEPS[stepIndex] || TRACKER_TUTORIAL_STEPS[0];
  const isFirst = stepIndex === 0;
  const isLast = stepIndex === TRACKER_TUTORIAL_STEPS.length - 1;

  return (
    <div className="fixed inset-0 z-[70] flex items-center justify-center bg-black/55 p-5">
      <div className="w-full max-w-md rounded-3xl bg-white p-5 shadow-2xl">
        <div className="mb-4 flex items-center justify-between gap-3">
          <div>
            <div className="text-xs font-semibold uppercase tracking-[0.18em] text-zinc-500">Gym Tracker Guide</div>
            <div className="mt-1 text-lg font-bold text-zinc-900">{step.title}</div>
          </div>
          <div className="rounded-full bg-zinc-100 px-2 py-1 text-xs font-semibold text-zinc-600">
            {stepIndex + 1}/{TRACKER_TUTORIAL_STEPS.length}
          </div>
        </div>

        <div className="overflow-hidden rounded-2xl border border-zinc-200 bg-zinc-50">
          <div className="bg-white p-2">
            <img
              src={step.imageSrc}
              alt={step.imageAlt}
              className="h-52 w-full rounded-xl object-contain"
            />
          </div>
          <div className="border-t border-zinc-200 p-4">
            <div className="text-xs font-semibold uppercase tracking-wide text-zinc-500">Look for</div>
            <div className="mt-1 text-base font-bold text-zinc-900">{step.focus}</div>
            <p className="mt-3 text-sm font-medium leading-6 text-zinc-800">{step.body}</p>
            {step.detail ? <p className="mt-2 text-sm leading-6 text-zinc-600">{step.detail}</p> : null}
            {step.examples?.length ? (
              <div className="mt-3 flex flex-wrap gap-2">
                {step.examples.map((example) => (
                  <span key={example} className="rounded-full bg-white px-3 py-1 text-xs font-semibold text-zinc-700">{example}</span>
                ))}
              </div>
            ) : null}
          </div>
        </div>

        <div className="mt-4 h-2 overflow-hidden rounded-full bg-zinc-100">
          <div
            className="h-full rounded-full bg-zinc-900 transition-all"
            style={{ width: `${((stepIndex + 1) / TRACKER_TUTORIAL_STEPS.length) * 100}%` }}
          />
        </div>

        <div className="mt-5 grid grid-cols-2 gap-3">
          <SmallButton onClick={() => onStepChange(Math.max(0, stepIndex - 1))} disabled={isFirst}>Back</SmallButton>
          <PrimaryButton onClick={() => (isLast ? onClose() : onStepChange(stepIndex + 1))}>{isLast ? "Done" : "Next"}</PrimaryButton>
        </div>
        <div className="mt-3 grid grid-cols-2 gap-3">
          <button onClick={onClose} className="rounded-xl px-3 py-2 text-sm font-semibold text-zinc-500 hover:bg-zinc-50">Skip</button>
          <button onClick={onNeverShowAgain} className="rounded-xl px-3 py-2 text-sm font-semibold text-zinc-500 hover:bg-zinc-50">Never Show Again</button>
        </div>
      </div>
    </div>
  );
}

function PathBar({ items }: { items: { label: string; onClick?: () => void }[] }) {
  return (
    <div className="flex flex-wrap items-center gap-2 rounded-2xl border border-zinc-200 bg-white p-2 text-sm font-medium shadow-sm">
      {items.map((item, index) => (
        <button
          key={`${item.label}-${index}`}
          onClick={item.onClick}
          className={`flex items-center gap-2 rounded-xl px-3 py-2 transition ${item.onClick ? "bg-zinc-50 hover:bg-zinc-100 text-zinc-800" : "bg-zinc-900 text-white cursor-default"}`}
        >
          {item.label}
          {index < items.length - 1 && <span className="text-zinc-400">›</span>}
        </button>
      ))}
    </div>
  );
}


// ===== AI SUMMARY ARCHITECTURE =====

type AISummaryLabel = "Exceptional Growth" | "Moderate Growth" | "Stable Growth" | "Contextual Decline";
type AISummaryTone = "exceptional" | "positive" | "neutral" | "contextual" | "baseline";
type AISummaryReportAccuracy = "High" | "Moderate" | "Low";
type AISummaryMarkerKind =
  | "output_rise"
  | "output_decline"
  | "output_plateau"
  | "output_volatility"
  | "weight_progression"
  | "consecutive_weight_progression"
  | "retained_output_under_weight"
  | "synchronized_progression"
  | "constraint_present"
  | "rebound"
  | "late_dip"
  | "explosive_jump"
  | "strong_finish"
  | "low_data";

type AISummaryStoryIdentity =
  | "stacked_progression"
  | "synchronized_advancement"
  | "hidden_progression"
  | "constraint_progression"
  | "steady_growth"
  | "stable_retention"
  | "mixed_signals"
  | "sustained_decline"
  | "decline_with_context"
  | "baseline_read";

type AISummarySlotKind =
  | "opener"
  | "dominant_achievement"
  | "highlight"
  | "supporting_context"
  | "structural_explanation"
  | "closer";

type AISummaryMarker = {
  kind: AISummaryMarkerKind;
  text: string;
  strength: number;
  seriesName?: string;
};

type AISummaryAchievement = {
  id: string;
  title: string;
  detail: string;
  strength: number;
  labelImpact: "supports" | "promotes" | "carries";
  markerKinds: AISummaryMarkerKind[];
};

type AISummaryInterpretedAchievementKind =
  | "exceptional_fallback"
  | "explosive_continuity"
  | "dominant_baseline_separation"
  | "escalating_constrained_progression"
  | "tight_baseline_range"
