const buildAISummaryInterpretedAchievements = (
  scorecard: AISummaryScorecard,
  classification: AISummaryClassification,
  achievements: AISummaryAchievement[],
  maxItems?: number
): AISummaryInterpretedAchievement[] => {
  const interpreted: AISummaryInterpretedAchievement[] = [];
  const bestWeightProfile = getAISummaryBestWeightProfile(scorecard);
  const bestOutputProfile = getAISummaryBestOutputProfile(scorecard);
  const controlledProgressionProfile = getAISummaryControlledProgressionProfile(scorecard);
  const constraintPhrase = getAISummaryConstraintPhrase(scorecard);
  const constraintSuffix = constraintPhrase ? ` ${constraintPhrase}` : "";
  const workingWithConstraintPhrase = getAISummaryWorkingWithConstraintPhrase(scorecard);
  const workingWithConstraintSuffix = workingWithConstraintPhrase ? ` ${workingWithConstraintPhrase}` : "";
  const trueConsistencyCheck = isAISummaryTrueConsistencyCheck(scorecard);
  const blockNoun = getAISummaryBlockNoun(scorecard);
  const bestProfile = bestOutputProfile || bestWeightProfile;
  const weightedConditioning = isAISummaryWeightedConditioningProfile(bestWeightProfile) || isAISummaryWeightedConditioningProfile(bestOutputProfile);
  const relevantTradeoff = hasAISummaryRelevantTradeoff(scorecard, bestWeightProfile || bestOutputProfile);
  const significantWeightGain = scorecard.seriesProfiles.some(hasAISummarySignificantWeightGain);
  const weightProgressionSeriesCount = scorecard.seriesProfiles.filter((profile) => profile.totalWeightIncrease > 0).length;
  const hasExerciseChange = scorecard.hasExerciseChange;
  const largeRelativeGain = hasAISummaryLargeRelativeGain(bestOutputProfile);
  const dominantBaselineSeparation = hasAISummaryDominantBaselineSeparation(bestOutputProfile);
  const tightBaselineRange = hasAISummaryTightBaselineRange(bestOutputProfile);
  const escalatingConstrainedProgression = hasAISummaryEscalatingConstrainedProgression(scorecard, bestOutputProfile);
  const sustainedPerformance = hasAISummarySustainedPerformancePattern(scorecard, bestOutputProfile);
  const outlierHiccup = hasAISummaryRecoveredHiccup(bestOutputProfile) && !relevantTradeoff;
  const preservedVolatility = hasAISummaryPreservedVolatility(scorecard, bestOutputProfile || bestWeightProfile);

  const context: AISummaryInterpretationContext = {
    interpreted,
    bestWeightProfile,
    bestOutputProfile,
    controlledProgressionProfile,
    constraintPhrase,
    constraintSuffix,
    workingWithConstraintSuffix,
    trueConsistencyCheck,
    blockNoun,
    bestProfile,
    weightedConditioning,
    relevantTradeoff,
    significantWeightGain,
    weightProgressionSeriesCount,
    hasExerciseChange,
    largeRelativeGain,
    dominantBaselineSeparation,
    tightBaselineRange,
    escalatingConstrainedProgression,
    sustainedPerformance,
    outlierHiccup,
    preservedVolatility,
  };

  if (classification.label === "Exceptional Growth") {
    buildAISummaryExceptionalInterpretedAchievements(scorecard, context);
  }

  if (classification.label === "Moderate Growth") {
    buildAISummaryModerateInterpretedAchievements(scorecard, context);
  }

  if (classification.label === "Stable Growth") {
    buildAISummaryStableInterpretedAchievements(scorecard, context);
  }

  if (classification.label === "Contextual Decline") {
    buildAISummaryContextualDeclineInterpretedAchievements(context);
  }

  if (!interpreted.length && achievements[0]) {
    pushAISummaryInterpretation(interpreted, {
      kind: "baseline_support",
      title: achievements[0].title,
      meaning: achievements[0].detail,
      summarySentence: achievements[0].detail,
      strength: achievements[0].strength,
      labelImpact: achievements[0].labelImpact,
      evidenceMarkerKinds: achievements[0].markerKinds,
    });
  }

  return interpreted
    .sort((a, b) => getAISummaryImpactRank(b.labelImpact) - getAISummaryImpactRank(a.labelImpact) || b.strength - a.strength)
    .slice(0, maxItems ?? (classification.label === "Exceptional Growth" ? 3 : 2));
};


const getAISummaryKeyFactorCategoryForSource = (sourceKind?: AISummaryKeyFactor["sourceKind"]): AISummaryKeyFactorCategory => {
  const source = String(sourceKind || "");

  if (["strong_output_ceiling", "strong_output_floor", "constraint_floor", "elevated_floor", "controlled_workflow", "tight_baseline_range"].includes(source)) return "range";
  if (["sustained_performance", "consistent_output_progression", "true_consistency"].includes(source)) return "sustained_performance";
  if (["consecutive_weight_progression", "weight_progression"].includes(source)) return "weight_progression";
  if (["substantial_weight_gain", "significant_weight_gain", "impactful_weight_progression", "weight_progression_streak"].includes(source)) return "weight_advancement";
  if (["constraint_work_area", "constraint_payoff", "constraint_present", "escalating_constrained_progression", "explosive_constrained_progression"].includes(source)) return "constraint_adaptation";
  if (["exercise_change_stability", "exercise_change_context"].includes(source)) return "exercise_change";
  if (["controlled_progression", "controlled_upward_drift", "outlier_hiccup_rebound", "output_rise"].includes(source)) return "trajectory";
  if (["preserved_volatility", "balanced_volatility", "late_dip", "rebound"].includes(source)) return "volatility_recovery";
  if (["tradeoff_recovery", "substantial_weight_tradeoff"].includes(source)) return "trade_off";
  if (["weighted_conditioning"].includes(source)) return "conditioning";
  if (["dominant_baseline_separation", "explosive_acceleration_retention", "high_octane_window", "explosive_jump"].includes(source)) return "exceptional_marker";

  return "general";
};

const getAISummaryKeyFactorCategoryForTitle = (title: string): AISummaryKeyFactorCategory => {
  const value = title.toLowerCase();

  if (/ceiling|floor|work area|work range|output range|workflow|range/.test(value)) return "range";
  if (/sustained|consistent output|consistency/.test(value)) return "sustained_performance";
  if (/consecutive weight|multiple weight|weight progression streak/.test(value)) return "weight_progression";
  if (/substantial weight|impactful weight|gradual weight|weight advancement/.test(value)) return "weight_advancement";
  if (/constraint|tempo|pause|ecc/.test(value)) return "constraint_adaptation";
  if (/exercise change/.test(value)) return "exercise_change";
  if (/trajectory|upward|drift|strong finish/.test(value)) return "trajectory";
  if (/volatility|recovery|rebound|hiccup/.test(value)) return "volatility_recovery";
  if (/trade-off|tradeoff/.test(value)) return "trade_off";
  if (/conditioning|cardio|rower|bike/.test(value)) return "conditioning";
  if (/exceptional|explosive|dominant|standout|relaunch|high-octane/.test(value)) return "exceptional_marker";

  return "general";
};

const getAISummaryKeyFactorCategory = (factor: AISummaryKeyFactor): AISummaryKeyFactorCategory => {
  if (factor.category) return factor.category;
  const sourceCategory = getAISummaryKeyFactorCategoryForSource(factor.sourceKind);
  return sourceCategory === "general" ? getAISummaryKeyFactorCategoryForTitle(factor.title) : sourceCategory;
};

const getAISummaryKeyFactorCategoryRank = (factor: AISummaryKeyFactor) => {
  const title = factor.title.toLowerCase();
  const source = String(factor.sourceKind || "");
  const category = getAISummaryKeyFactorCategory(factor);

  if (category === "range") {
    if (/ceiling/.test(title) || source === "strong_output_ceiling") return 35;
    if (/floor/.test(title) || source === "strong_output_floor" || source === "constraint_floor" || source === "elevated_floor") return 34;
    return 12;
  }

  if (category === "sustained_performance") {
    if (/sustained/.test(title) || source === "sustained_performance") return 32;
    return 20;
  }

  if (category === "weight_progression") {
    if (/consecutive/.test(title) || source === "consecutive_weight_progression") return 34;
    if (/multiple/.test(title)) return 22;
    return 16;
  }

  if (category === "weight_advancement") {
    if (/substantial/.test(title) || source === "substantial_weight_gain") return 34;
    if (/impactful|significant/.test(title) || source === "significant_weight_gain" || source === "impactful_weight_progression") return 24;
    return 14;
  }

  if (category === "constraint_adaptation") {
    if (/explosive/.test(title) || source === "explosive_constrained_progression") return 34;
    if (/escalating/.test(title) || source === "escalating_constrained_progression") return 28;
    return 20;
  }

  if (category === "exercise_change") {
    if (/stability|stable/.test(title) || source === "exercise_change_stability") return 30;
    return 18;
  }

  if (category === "trajectory") {
    if (/controlled upward|controlled progression/.test(title) || source === "controlled_progression") return 28;
    if (/drift|strong finish|rebound/.test(title)) return 20;
    return 14;
  }

  if (category === "volatility_recovery") {
    if (/recovered|recovery|rebound/.test(title)) return 28;
    if (/balanced/.test(title)) return 22;
    return 16;
  }

  if (category === "trade_off") return 18;
  if (category === "conditioning") return /weighted/.test(title) || source === "weighted_conditioning" ? 26 : 16;
  if (category === "exceptional_marker") return 34;

  return 10;
};

const getAISummaryKeyFactorPriority = (factor: AISummaryKeyFactor) => {
  const title = factor.title.toLowerCase();
  const source = String(factor.sourceKind || "");
  const category = getAISummaryKeyFactorCategory(factor);

  if (category === "exceptional_marker" || /exceptional|explosive|dominant|standout|relaunch/.test(title) || factor.priority >= 95) return factor.priority + 18;
  if (category === "weight_progression") return factor.priority + 16;
  if (category === "range" && (/ceiling|floor/.test(title) || source === "strong_output_ceiling" || source === "strong_output_floor" || source === "constraint_floor" || source === "elevated_floor")) return factor.priority + 14;
  if (category === "sustained_performance") return factor.priority + 12;
  if (category === "exercise_change") return factor.priority + 11;
  if (category === "constraint_adaptation") return factor.priority + 10;
  if (category === "weight_advancement") return factor.priority + 9;
  if (category === "conditioning") return factor.priority + 6;
  if (category === "trade_off") return factor.priority + 5;
  if (category === "range") return factor.priority - 6;
  return factor.priority;
};

const addAISummaryKeyFactor = (factors: AISummaryKeyFactor[], factor: AISummaryKeyFactor) => {
  const normalizedTitle = factor.title.toLowerCase().replace(/[^a-z0-9]+/g, " ").trim();
  const normalizedFactor = { ...factor, category: factor.category || getAISummaryKeyFactorCategory(factor) };
  const alreadyExists = factors.some((existing) => {
    const existingTitle = existing.title.toLowerCase().replace(/[^a-z0-9]+/g, " ").trim();
    return existing.id === normalizedFactor.id || existingTitle === normalizedTitle;
  });

  if (!alreadyExists) factors.push(normalizedFactor);
};

const getAISummaryKeyFactorDetail = (achievement: AISummaryInterpretedAchievement) => {
  switch (achievement.kind) {
    case "strong_output_floor":
    case "constraint_floor":
    case "elevated_floor":
      return "You established a reliable working floor and kept the block from falling below that level.";
    case "strong_output_ceiling":
      return "You reached the top working level and kept returning to it as demand increased.";
    case "sustained_performance":
      return "You sustained the output structure across an extended stretch while demand continued to rise.";
    case "consistent_output_progression":
      return "You kept output steady while weight progression became the main source of added difficulty.";
    case "constraint_work_area":
    case "constraint_payoff":
    case "escalating_constrained_progression":
    case "explosive_constrained_progression":
      return "You preserved useful output while working under added constraint demand.";
    case "exercise_change_stability":
    case "exercise_change_context":
      return "The block stayed stable even after the exercise changed mid-program.";
    case "substantial_weight_gain":
    case "significant_weight_gain":
      return "Weight progression was large enough to meaningfully shape how this graph should be read.";
    case "tradeoff_recovery":
    case "substantial_weight_tradeoff":
      return "Rising demands produced a temporary output trade-off while progression continued.";
    case "weighted_conditioning":
      return "Weight progression gave this conditioning-style result more value than the output line alone shows.";
    case "controlled_progression":
      return "The graph stayed controlled while gradually moving in a positive direction.";
    case "preserved_volatility":
    case "balanced_volatility":
      return "The block moved through fluctuation without losing its overall working structure.";
    default:
      return achievement.meaning.replace(/^The athlete\s+/i, "You ").replace(/\.$/, ".");
  }
};

const getAISummaryKeyFactorCategoryForInterpretation = (achievement: AISummaryInterpretedAchievement): AISummaryKeyFactorCategory =>
  getAISummaryKeyFactorCategoryForSource(achievement.kind);


const getAISummaryKeyFactorFamily = (factor: AISummaryKeyFactor): AISummaryKeyFactorFamily => {
  const title = factor.title.toLowerCase();
  const source = String(factor.sourceKind || "").toLowerCase();
  const detail = factor.detail.toLowerCase();
  const text = `${title} ${source} ${detail}`;

  if (
    /ceiling|floor|work area|work range|output range|controlled work range|controlled workflow|tight_baseline_range|strong_output_ceiling|strong_output_floor|constraint_floor|elevated_floor/.test(text)
  ) {
    return "output_structure";
  }

  if (/sustained|consistent output|consistency|sustained_performance|consistent_output_progression|true_consistency/.test(text)) {
    return "sustained_performance";
  }

  if (
    /explosive acceleration|explosive output jump|explosive jump|output rise|output_rise|finished .* above baseline|primary progress pattern|controlled progression|controlled upward|upward drift|dominant baseline separation|dominant_baseline_separation|explosive_acceleration_retention|explosive_jump/.test(text)
  ) {
    return "progress_pattern";
  }

  if (
    /output held under rising demand|retained output under weight|retained_output_under_weight|retained-output-under-weight|consecutive weight|multiple weight|weight progression streak|consecutive_weight_progression|weight_progression/.test(text)
  ) {
    return "weight_output";
  }

  if (
    /substantial weight|impactful weight|significant weight|weight advancement|substantial_weight_gain|significant_weight_gain|impactful_weight_progression/.test(text)
  ) {
    return "weight_advancement";
  }

  if (/constraint|tempo|pause|ecc|constraint_present|constraint_work_area|constraint_payoff|escalating_constrained_progression|explosive_constrained_progression/.test(text)) {
    return "constraint_adaptation";
  }

  if (/exercise change|exercise_change/.test(text)) return "exercise_change";
  if (/volatility|recovery|rebound|hiccup|late_dip|balanced_volatility|preserved_volatility/.test(text)) return "volatility_recovery";
  if (/trade-off|tradeoff|tradeoff_recovery|substantial_weight_tradeoff/.test(text)) return "trade_off";
  if (/conditioning|cardio|rower|bike|weighted_conditioning/.test(text)) return "conditioning";

  return "general";
};

const getAISummaryKeyFactorFamilyRank = (factor: AISummaryKeyFactor) => {
  const title = factor.title.toLowerCase();
  const source = String(factor.sourceKind || "").toLowerCase();
  const detail = factor.detail.toLowerCase();
  const text = `${title} ${source} ${detail}`;
  const family = getAISummaryKeyFactorFamily(factor);

  if (family === "output_structure") {
    if (/ceiling|strong_output_ceiling/.test(text)) return 40;
    if (/floor|strong_output_floor|constraint_floor|elevated_floor/.test(text)) return 39;
    if (/sustained/.test(text)) return 30;
    return 16;
  }

  if (family === "progress_pattern") {
    if (/explosive acceleration.*retention|explosive_acceleration_retention/.test(text)) return 42;
    if (/dominant baseline separation|dominant_baseline_separation/.test(text)) return 40;
    if (/explosive output jump|explosive jump|explosive_jump/.test(text)) return 34;
    if (/controlled progression|controlled upward/.test(text)) return 28;
    if (/finished .* above baseline|output rise|output_rise/.test(text)) return 18;
    if (/primary progress pattern/.test(text)) return 8;
    return 12;
  }

  if (family === "weight_output") {
    if (/output held under rising demand|retained output under weight|retained_output_under_weight/.test(text)) return 40;
    if (/structure retained|retained adaptation/.test(text)) return 36;
    if (/consecutive/.test(text)) return 30;
    if (/multiple/.test(text)) return 22;
    return 14;
  }

  if (family === "weight_advancement") {
    if (/substantial/.test(text) || source === "substantial_weight_gain") return 34;
    if (/impactful|significant/.test(text) || source === "significant_weight_gain" || source === "impactful_weight_progression") return 24;
    return 14;
  }

  if (family === "constraint_adaptation") {
    if (/explosive/.test(text) || source === "explosive_constrained_progression") return 34;
    if (/escalating/.test(text) || source === "escalating_constrained_progression") return 28;
    return 18;
  }

  if (family === "exercise_change") return /stability|stable/.test(text) ? 30 : 18;
  if (family === "volatility_recovery") return /recovered|recovery|rebound/.test(text) ? 28 : /balanced/.test(text) ? 22 : 16;
  if (family === "trade_off") return 18;
  if (family === "conditioning") return /weighted/.test(text) || source === "weighted_conditioning" ? 26 : 16;

  return 10;
};

const selectAISummaryKeyFactorFamilyWinners = (factors: AISummaryKeyFactor[]) => {
  const byFamily = new Map<AISummaryKeyFactorFamily, AISummaryKeyFactor>();

  factors.forEach((factor) => {
    const family = getAISummaryKeyFactorFamily(factor);
    const current = byFamily.get(family);
    const familyRank = getAISummaryKeyFactorFamilyRank(factor);
    const currentFamilyRank = current ? getAISummaryKeyFactorFamilyRank(current) : -Infinity;
    const priority = getAISummaryKeyFactorPriority(factor);
    const currentPriority = current ? getAISummaryKeyFactorPriority(current) : -Infinity;

    if (!current || familyRank > currentFamilyRank || (familyRank === currentFamilyRank && (priority > currentPriority || (priority === currentPriority && factor.strength > current.strength)))) {
      byFamily.set(family, factor);
    }
  });

  return Array.from(byFamily.values());
};

const selectAISummaryKeyFactorCategoryWinners = (factors: AISummaryKeyFactor[]) => {
  const byCategory = new Map<AISummaryKeyFactorCategory, AISummaryKeyFactor>();

  factors.forEach((factor) => {
    const category = getAISummaryKeyFactorCategory(factor);
    const current = byCategory.get(category);
    const categoryRank = getAISummaryKeyFactorCategoryRank(factor);
    const currentCategoryRank = current ? getAISummaryKeyFactorCategoryRank(current) : -Infinity;
    const priority = getAISummaryKeyFactorPriority(factor);
    const currentPriority = current ? getAISummaryKeyFactorPriority(current) : -Infinity;

    if (!current || categoryRank > currentCategoryRank || (categoryRank === currentCategoryRank && (priority > currentPriority || (priority === currentPriority && factor.strength > current.strength)))) {
      byCategory.set(category, { ...factor, category });
    }
  });

  return Array.from(byCategory.values());
};

const dedupeAISummaryKeyFactors = (factors: AISummaryKeyFactor[]) => {
  const seenIds = new Set<string>();
  const seenTitles = new Set<string>();

  return factors.filter((factor) => {
    const normalizedTitle = factor.title.toLowerCase().replace(/[^a-z0-9]+/g, " ").trim();
    if (seenIds.has(factor.id) || seenTitles.has(normalizedTitle)) return false;
    seenIds.add(factor.id);
    seenTitles.add(normalizedTitle);
    return true;
  });
};

const buildAISummaryKeyFactors = (
  scorecard: AISummaryScorecard,
  classification: AISummaryClassification,
  achievements: AISummaryAchievement[],
  interpretedAchievements: AISummaryInterpretedAchievement[]
): AISummaryKeyFactor[] => {
  const factors: AISummaryKeyFactor[] = [];
  const classificationPriorityBoost = classification.label === "Exceptional Growth" ? 6 : classification.label === "Moderate Growth" ? 3 : 0;
  const bestOutputProfile = getAISummaryBestOutputProfile(scorecard);
  const bestWeightProfile = getAISummaryBestWeightProfile(scorecard);
  const hasFloor = hasAISummaryStrongOutputFloor(scorecard, bestOutputProfile) || interpretedAchievements.some((item) => item.kind === "strong_output_floor" || item.kind === "constraint_floor" || item.kind === "elevated_floor");
  const hasCeiling = hasAISummaryStrongOutputCeiling(scorecard, bestOutputProfile) || interpretedAchievements.some((item) => item.kind === "strong_output_ceiling");
  const hasSpecificRangePromotion = hasFloor || hasCeiling || interpretedAchievements.some((item) => item.kind === "sustained_performance");
  const genericRangeKinds: AISummaryInterpretedAchievementKind[] = ["controlled_workflow", "constraint_work_area", "preserved_volatility", "tight_baseline_range"];

  interpretedAchievements.forEach((achievement) => {
    if (hasSpecificRangePromotion && genericRangeKinds.includes(achievement.kind)) return;

    addAISummaryKeyFactor(factors, {
      id: `interpretation-${achievement.kind}`,
      title: achievement.title,
      detail: getAISummaryKeyFactorDetail(achievement),
      strength: achievement.strength,
      priority: getAISummaryImpactRank(achievement.labelImpact) * 30 + achievement.strength * 20 + classificationPriorityBoost,
      category: getAISummaryKeyFactorCategoryForInterpretation(achievement),
      sourceKind: achievement.kind,
    });
  });

  if (hasFloor && !factors.some((factor) => /floor/i.test(factor.title))) {
    addAISummaryKeyFactor(factors, {
      id: "strong-output-floor-factor",
      title: "Strong Output Floor",
      detail: "You established a reliable working floor and kept the block from falling below that level.",
      strength: 0.84,
      priority: 82,
      category: "range",
      sourceKind: "output_plateau",
    });
  }

  if (hasCeiling && !factors.some((factor) => /ceiling/i.test(factor.title))) {
    addAISummaryKeyFactor(factors, {
      id: "strong-output-ceiling-factor",
      title: "Strong Output Ceiling",
      detail: "You reached the top working level and kept returning to it as demand increased.",
      strength: 0.84,
      priority: 82,
      category: "range",
      sourceKind: "output_plateau",
    });
  }

  if (scorecard.maxConsecutiveWeightIncreaseCount >= 2 && bestWeightProfile) {
    const count = scorecard.maxConsecutiveWeightIncreaseCount;
    addAISummaryKeyFactor(factors, {
      id: "consecutive-weight-increases-factor",
      title: count >= 4 ? `${count} Consecutive Weight Increases` : "Consecutive Weight Increases",
      detail: count >= 4
        ? `Weight increased across ${count} consecutive progressions while the block kept its structure.`
        : "You increased weight in consecutive sessions, adding demand without losing the thread of the block.",
      strength: Math.min(0.94, 0.64 + count * 0.07),
      priority: 78 + count * 3,
      category: "weight_progression",
      sourceKind: "consecutive_weight_progression",
    });
  }

  if ((getAISummarySubstantialWeightProgression(scorecard) || getAISummaryImpactfulWeightProgression(scorecard)) && bestWeightProfile) {
    const substantial = getAISummarySubstantialWeightProgression(scorecard);
    addAISummaryKeyFactor(factors, {
      id: substantial ? "substantial-weight-advancement-factor" : "impactful-weight-advancement-factor",
      title: substantial ? "Substantial Weight Progression" : "Impactful Weight Progression",
      detail: substantial
        ? "The amount of weight added was large enough to meaningfully raise the demand of the block."
        : "The weight increases were meaningful enough to shape how this progress should be read.",
      strength: substantial ? 0.86 : 0.78,
      priority: substantial ? 84 : 76,
      category: "weight_advancement",
      sourceKind: substantial ? "substantial_weight_gain" : "significant_weight_gain",
    });
  }

  if (scorecard.hasConstraints && scorecard.hasRetainedOutputUnderWeight && !factors.some((factor) => /constraint|tempo|pause|ecc/i.test(factor.title))) {
    addAISummaryKeyFactor(factors, {
      id: "constraint-adaptation-factor",
      title: "Constraint Adaptation",
      detail: "You preserved useful output while working under added constraint demand.",
      strength: 0.82,
      priority: 80,
      category: "constraint_adaptation",
      sourceKind: "constraint_present",
    });
  }

  if (hasAISummaryRelevantTradeoff(scorecard, bestWeightProfile || bestOutputProfile)) {
    addAISummaryKeyFactor(factors, {
      id: "trade-off-factor",
      title: "Trade-Off",
      detail: "Rising demands produced a temporary reduction in output while progression continued.",
      strength: 0.68,
      priority: 62,
      category: "trade_off",
      sourceKind: "late_dip",
    });
  }

  achievements.forEach((achievement) => {
    if (factors.length >= 12) return;
    addAISummaryKeyFactor(factors, {
      id: `achievement-${achievement.id}`,
      title: achievement.title,
      detail: achievement.detail,
      strength: achievement.strength,
      priority: getAISummaryImpactRank(achievement.labelImpact) * 26 + achievement.strength * 18 + classificationPriorityBoost,
      category: getAISummaryKeyFactorCategoryForSource(achievement.id) === "general" ? getAISummaryKeyFactorCategoryForTitle(achievement.title) : getAISummaryKeyFactorCategoryForSource(achievement.id),
      sourceKind: achievement.id,
    });
  });

  return dedupeAISummaryKeyFactors(
    selectAISummaryKeyFactorCategoryWinners(selectAISummaryKeyFactorFamilyWinners(factors))
  )
    .sort((a, b) => getAISummaryKeyFactorPriority(b) - getAISummaryKeyFactorPriority(a) || b.strength - a.strength)
    .slice(0, 6);
};

const buildAISummaryHighlightsFromInterpretations = (interpretedAchievements: AISummaryInterpretedAchievement[]): AISummaryHighlight[] =>
  interpretedAchievements
    .filter((achievement) => achievement.labelImpact === "carries" || achievement.strength >= 0.82)
    .map((achievement) => ({
      title: achievement.title,
      detail: achievement.meaning,
      strength: achievement.strength,
    }))
    .slice(0, 2);

const shouldUseAISummaryHighlightSlot = (classification: AISummaryClassification, highlight?: AISummaryHighlight) => {
  if (!highlight) return false;
  if (classification.label === "Exceptional Growth") return highlight.strength >= 0.68;
  if (classification.label === "Moderate Growth") return highlight.strength >= 0.78;
  return false;
};


const buildAISummaryHighlightSentence = (highlight: AISummaryHighlight, scorecard: AISummaryScorecard) => {
  const title = highlight.title.trim();
  const detail = highlight.detail.trim();
  const constraintPhrase = getAISummaryConstraintPhrase(scorecard);

  if (/consecutive weight increases/i.test(title)) {
    return `You set the tone with ${title.toLowerCase()}${constraintPhrase ? ` ${constraintPhrase}` : ""}.`;
  }

  if (/above baseline/i.test(title)) {
    return `${title} gives the work a clear positive finish.`;
  }

  if (/explosive|baseline separation|retained/i.test(title)) {
    return detail || "You created separation from your baseline and kept building from there.";
  }

  return detail || title;
};

const getAISummarySlotPlan = (classification: AISummaryClassification, story: AISummaryStory): AISummarySlotPlan => {
  const basePlan: AISummarySlotPlan = {
    allowSecondaryHighlight: false,
    secondaryHighlightMinStrength: 0.9,
    allowFallbackHighlight: classification.label === "Exceptional Growth" || classification.label === "Moderate Growth",
    allowStructuralExplanation: story.needsStructuralExplanation,
    allowCloser: classification.label !== "Contextual Decline",
  };

  if (classification.label === "Exceptional Growth") {
    return {
      ...basePlan,
      allowSecondaryHighlight: true,
      secondaryHighlightMinStrength:
        story.identity === "stacked_progression" ||
        story.identity === "synchronized_advancement" ||
        story.identity === "constraint_progression"
          ? 0.86
          : 0.92,
      allowFallbackHighlight: true,
      allowStructuralExplanation: story.needsStructuralExplanation,
      allowCloser: true,
    };
  }

  if (classification.label === "Moderate Growth") {
    return {
      ...basePlan,
      allowSecondaryHighlight: false,
      secondaryHighlightMinStrength: 0.78,
      allowFallbackHighlight: true,
      allowStructuralExplanation: story.needsStructuralExplanation,
      allowCloser: true,
    };
  }

  if (classification.label === "Stable Growth") {
    return {
      ...basePlan,
      allowFallbackHighlight: false,
      allowStructuralExplanation: story.needsStructuralExplanation,
      allowCloser: false,
    };
  }

  return {
    ...basePlan,
    allowFallbackHighlight: false,
    allowStructuralExplanation: true,
    allowCloser: false,
  };
};

const isAISummaryPrestigeInterpretation = (interpretation?: AISummaryInterpretedAchievement) =>
  !!interpretation &&
  (
    interpretation.kind === "dominant_baseline_separation" ||
    interpretation.kind === "explosive_continuity" ||
    interpretation.kind === "escalating_constrained_progression" ||
    interpretation.kind === "explosive_constrained_progression" ||
    interpretation.kind === "explosive_conditioning_climb" ||
    interpretation.kind === "vertical_relaunch_conditioning"
  );

const selectAISummarySecondarySlotCandidate = (
  classification: AISummaryClassification,
  slotPlan: AISummarySlotPlan,
  primaryInterpretation: AISummaryInterpretedAchievement | undefined,
  secondaryInterpretations: AISummaryInterpretedAchievement[]
) => {
  const primaryIsPrestige = isAISummaryPrestigeInterpretation(primaryInterpretation);
  const exerciseChangeCandidate = secondaryInterpretations.find((item) => item.kind === "exercise_change_stability" || item.kind === "exercise_change_context");
  if (exerciseChangeCandidate && primaryInterpretation?.kind !== "exercise_change_stability") return exerciseChangeCandidate;

  if (!slotPlan.allowSecondaryHighlight) return undefined;

  return secondaryInterpretations.find((item) => {
    if (primaryIsPrestige && item.kind === "retained_adaptation") return false;
    if (classification.label === "Exceptional Growth") {
      return !primaryIsPrestige && (item.strength >= slotPlan.secondaryHighlightMinStrength || item.labelImpact !== "supports");
    }
    return item.strength >= slotPlan.secondaryHighlightMinStrength;
  });
};

const normalizeAISummarySlotText = (text: string) =>
  text
    .replace(/\bThe clearest (highlight|win) was\b/gi, "")
    .replace(/\bdouble ([A-Z]+)\/\1 constraints\b/g, "double $1 constraints")
    .replace(/\bthe read pointed upward\b/gi, "the progression stayed positive")
    .replace(/\s+/g, " ")
    .trim();

const locateAISummaryStory = (scorecard: AISummaryScorecard, classification: AISummaryClassification): AISummaryStory => {
  if (classification.label === "Exceptional Growth") {
    if (scorecard.hasRetainedOutputUnderWeight && scorecard.hasConstraints) {
      return { identity: "constraint_progression", label: classification.label, tone: "exceptional", needsStructuralExplanation: true };
    }
    if (scorecard.hasSynchronizedProgression) {
      return { identity: "synchronized_advancement", label: classification.label, tone: "exceptional", needsStructuralExplanation: false };
    }
    return { identity: scorecard.hasExplosiveJump ? "stacked_progression" : "hidden_progression", label: classification.label, tone: "exceptional", needsStructuralExplanation: !scorecard.hasExplosiveJump };
  }

  if (classification.label === "Moderate Growth") {
    if (scorecard.hasRetainedOutputUnderWeight) {
      return { identity: "stable_retention", label: classification.label, tone: "positive", needsStructuralExplanation: true };
    }
    return { identity: "steady_growth", label: classification.label, tone: "positive", needsStructuralExplanation: false };
  }

  if (classification.label === "Contextual Decline") {
    return { identity: "decline_with_context", label: classification.label, tone: "contextual", needsStructuralExplanation: true };
  }

  return { identity: scorecard.hasRebound ? "mixed_signals" : "baseline_read", label: classification.label, tone: "neutral", needsStructuralExplanation: false };
};

const formatAISummaryNumber = (value: number) => {
  const rounded = Math.round(value * 10) / 10;
  return Number.isInteger(rounded) ? String(rounded) : rounded.toFixed(1);
};

const getAISummaryHeadline = (classification: AISummaryClassification, _story: AISummaryStory) => classification.label;


const buildAISummaryOpeningSlot = (scorecard: AISummaryScorecard, classification: AISummaryClassification, _story: AISummaryStory): AISummaryResolvedSlot => {
  const blockNoun = getAISummaryBlockNoun(scorecard);

  if (classification.label === "Exceptional Growth") {
    return { kind: "opener", text: `You crushed this ${blockNoun}!`, importance: 1 };
  }

  if (classification.label === "Moderate Growth") {
    if ((scorecard.hasConstraints && scorecard.hasRetainedOutputUnderWeight) || (scorecard.hasRetainedOutputUnderWeight && scorecard.totalWeightIncreaseCount >= 5)) return { kind: "opener", text: "Impressive performance.", importance: 0.9 };
    if (scorecard.hasRetainedOutputUnderWeight || scorecard.maxConsecutiveWeightIncreaseCount >= 3) return { kind: "opener", text: "Strong work here.", importance: 0.88 };
    if (scorecard.hasExplosiveJump) return { kind: "opener", text: "This block came together well.", importance: 0.86 };
    return { kind: "opener", text: "You performed well here.", importance: 0.82 };
  }

  if (classification.label === "Contextual Decline") {
    return { kind: "opener", text: "", importance: 0.76 };
  }

  if (isAISummaryTrueConsistencyCheck(scorecard)) {
    return { kind: "opener", text: "This block functioned more as a consistency-focused session than a progression-focused one.", importance: 0.68 };
  }

  return { kind: "opener", text: "You did well.", importance: 0.72 };
};

const buildAISummaryAchievementSentence = (
  scorecard: AISummaryScorecard,
  classification: AISummaryClassification,
  achievement?: AISummaryAchievement
) => {
  if (!achievement) return "";

  if (classification.label === "Stable Growth") {
    return achievement.detail;
  }

  if (achievement.id === "retained-output-under-weight") {
    return achievement.detail.replace("maintained its working range", "maintained a stable working range");
  }

  if (achievement.id === "explosive-output-jump") {
    return achievement.detail;
  }

  if (achievement.id === "four-plus-weight-increases") {
    return achievement.detail;
  }

  if (achievement.id === "synchronized-progression" && classification.label === "Exceptional Growth") {
    return "Both exercises helped create distance from the starting baseline and kept the higher structure intact.";
  }

  if (scorecard.mode === "single" && classification.label === "Moderate Growth" && achievement.id === "finished-above-start") {
    return achievement.detail.replace("which keeps the read pointed upward", "which is a strong sign of conditioning progress");
  }

  return achievement.detail;
};


const buildAISummaryExerciseChangeContextSentence = (
  scorecard: AISummaryScorecard,
  classification: AISummaryClassification,
  interpretedAchievements: AISummaryInterpretedAchievement[] = []
) => {
  if (classification.label !== "Moderate Growth" && classification.label !== "Exceptional Growth") return "";
  if (!scorecard.hasExerciseChange) return "";
  const stabilitySentence = interpretedAchievements.find((item) => item.kind === "exercise_change_stability")?.summarySentence || "";
  if (/mid-program exercise change/i.test(stabilitySentence)) return "";

  const kinds = interpretedAchievements.map((item) => item.kind);
  if (kinds.includes("strong_output_ceiling")) return "Despite a mid-program exercise change, you maintained a strong ceiling.";
  if (kinds.includes("strong_output_floor")) return "Despite a mid-program exercise change, you maintained a workable floor.";
  if (kinds.includes("controlled_progression")) return "Despite a mid-program exercise change, the progression still moved upward.";
  if (kinds.includes("tradeoff_recovery")) return "Despite a mid-program exercise change, you kept the larger progression intact.";
  return "Despite a mid-program exercise change, you maintained your output range.";
};

const buildAISummaryStructuralSentence = (
  scorecard: AISummaryScorecard,
  classification: AISummaryClassification,
  story: AISummaryStory,
  interpretedAchievements: AISummaryInterpretedAchievement[] = []
) => {
  const bestOutputProfile = getAISummaryBestOutputProfile(scorecard);

  if (classification.label === "Contextual Decline") {
    return "";
  }

  if (classification.label === "Stable Growth") {
    return "";
  }

  if (classification.label === "Exceptional Growth") {
    return "";
  }

  if (classification.label === "Moderate Growth") {
    const hasInterpretation = interpretedAchievements.length > 0;
    if (hasInterpretation) return "";
    if (story.needsStructuralExplanation && scorecard.hasRetainedOutputUnderWeight) {
      return "The work became meaningful through the higher demand you handled, not just the output line.";
    }
    if (bestOutputProfile && bestOutputProfile.outputDelta > 0 && !scorecard.hasLateDip) {
      return `${bestOutputProfile.exerciseName} finished ${formatAISummaryDeltaWithMetric(bestOutputProfile.outputDelta, bestOutputProfile)} above where it started.`;
    }
  }

  return "";
};

const getAISummaryCloserText = (
  scorecard: AISummaryScorecard,
  classification: AISummaryClassification,
  interpretedAchievements: AISummaryInterpretedAchievement[]
) => {
  if (classification.label === "Exceptional Growth") return "Outstanding work!";
  if (classification.label === "Contextual Decline") return "";
  if (classification.label === "Stable Growth") {
    if (interpretedAchievements.some((item) => item.kind === "true_consistency_check")) return "";
    if (interpretedAchievements.some((item) => item.kind === "controlled_progression" || item.kind === "balanced_volatility")) return "";
    return "";
  }

  const kinds = interpretedAchievements.map((item) => item.kind);
  const highAchievementEnergy =
    kinds.includes("substantial_weight_tradeoff") ||
    kinds.includes("constraint_work_area") ||
    (kinds.includes("substantial_weight_gain") && (scorecard.hasConstraints || scorecard.totalWeightIncreaseCount >= 5)) ||
    (kinds.includes("tradeoff_recovery") && scorecard.totalWeightIncreaseCount >= 3);
  if (highAchievementEnergy) return "Great job.";
  if (kinds.includes("sustained_performance")) return "Great job.";
  if (kinds.includes("tradeoff_recovery")) return "Good job.";
  if (kinds.includes("tight_baseline_range")) return classification.label === "Moderate Growth" ? "Good job." : "";
  if (kinds.includes("weighted_conditioning") || kinds.includes("preserved_volatility")) return "Good job.";
  if (kinds.includes("constraint_floor") || kinds.includes("controlled_workflow") || kinds.includes("consistent_output_progression") || kinds.includes("strong_output_floor") || kinds.includes("strong_output_ceiling")) return "Good job.";
  if (scorecard.hasConstraints || scorecard.hasRetainedOutputUnderWeight) return "Good job.";
  return "Good work.";
};

const adjustAISummaryCloserForThemeRepetition = (closer: string, existingSlots: AISummaryResolvedSlot[]) => {
  if (!closer) return closer;
  const priorText = existingSlots.map((slot) => slot.text).join(" ").toLowerCase();
  if (/\b(good|great|outstanding)\s+(job|work)\b[.!]?\s*$/.test(priorText)) return "";
  if (/\b(this style of workflow defines a great workout|this type of discipline|structure under rising demand reflects excellent discipline)\b/.test(priorText)) return "Good job.";

  return closer;
};


const composeAISummarySlots = (
  scorecard: AISummaryScorecard,
  classification: AISummaryClassification,
  story: AISummaryStory,
  achievements: AISummaryAchievement[],
  interpretedAchievements: AISummaryInterpretedAchievement[],
  highlights: AISummaryHighlight[]
): AISummaryResolvedSlot[] => {
  const slots: AISummaryResolvedSlot[] = [];
  const slotPlan = getAISummarySlotPlan(classification, story);
  const primaryAchievement = achievements[0];
  const primaryInterpretation = interpretedAchievements[0];
  const secondaryInterpretations = interpretedAchievements.slice(1);
  const primaryHighlight = highlights[0];

  const addSlot = (slot: AISummaryResolvedSlot | null | undefined) => {
    if (!slot?.text.trim()) return;
    const normalizedText = normalizeAISummarySlotText(slot.text);
    if (!normalizedText) return;
    slots.push({ ...slot, text: normalizedText });
  };

  addSlot(buildAISummaryOpeningSlot(scorecard, classification, story));

  const achievementSentence = primaryInterpretation?.summarySentence || buildAISummaryAchievementSentence(scorecard, classification, primaryAchievement);
  if (achievementSentence) {
    addSlot({
      kind: "dominant_achievement",
      text: achievementSentence,
      importance: primaryInterpretation?.strength || primaryAchievement?.strength || 0.7,
    });
  }

  const usefulSecondary = selectAISummarySecondarySlotCandidate(
    classification,
    slotPlan,
    primaryInterpretation,
    secondaryInterpretations
  );

  if (usefulSecondary && usefulSecondary.summarySentence !== achievementSentence) {
    addSlot({ kind: "highlight", text: usefulSecondary.summarySentence, importance: usefulSecondary.strength });
  } else if (slotPlan.allowFallbackHighlight && !primaryInterpretation && shouldUseAISummaryHighlightSlot(classification, primaryHighlight)) {
    const highlightText = buildAISummaryHighlightSentence(primaryHighlight, scorecard);
    if (highlightText && highlightText !== achievementSentence) {
      addSlot({ kind: "highlight", text: highlightText, importance: primaryHighlight.strength });
    }
  }

  const exerciseChangeContext = buildAISummaryExerciseChangeContextSentence(scorecard, classification, interpretedAchievements);
  const exerciseChangeAlreadyMentioned = slots.some((slot) => /mid-program exercise change/i.test(slot.text));
  if (exerciseChangeContext && exerciseChangeContext !== achievementSentence && !exerciseChangeAlreadyMentioned) {
    addSlot({ kind: "supporting_context", text: exerciseChangeContext, importance: 0.66 });
  }

  if (slotPlan.allowStructuralExplanation) {
    const structuralSentence = buildAISummaryStructuralSentence(scorecard, classification, story, interpretedAchievements);
    if (structuralSentence) {
      addSlot({
        kind: classification.label === "Contextual Decline" || classification.label === "Stable Growth" ? "structural_explanation" : "supporting_context",
        text: structuralSentence,
        importance: 0.58,
      });
    }
  }

  if (slotPlan.allowCloser) {
    const closer = adjustAISummaryCloserForThemeRepetition(getAISummaryCloserText(scorecard, classification, interpretedAchievements), slots);
    if (closer) addSlot({ kind: "closer", text: closer, importance: 0.35 });
  }

  const seen = new Set<string>();
  return slots.filter((slot) => {
    const normalized = slot.text.toLowerCase().replace(/[^a-z0-9]+/g, " ").trim();
    const shortKey = normalized
      .replace(/\b(the|a|an|this|that|with|while|under|through|and|or|but|it|its|you|your|graph|block|exercise)\b/g, "")
      .replace(/\s+/g, " ")
      .trim();
    if (!normalized || seen.has(normalized) || seen.has(shortKey)) return false;
    seen.add(normalized);
    seen.add(shortKey);
    return true;
  });
};

const cleanupAISummaryText = (slots: AISummaryResolvedSlot[]) => {
  const sentence = slots
    .sort((a, b) => {
      const order: Record<AISummarySlotKind, number> = {
        opener: 1,
        dominant_achievement: 2,
        highlight: 3,
        supporting_context: 4,
        structural_explanation: 5,
        closer: 6,
      };
      return order[a.kind] - order[b.kind];
    })
    .map((slot) => slot.text.trim())
    .filter(Boolean)
    .join(" ")
    .replace(/You performed well here\. Despite a hiccup, you performed well here\./g, "Despite a hiccup, you performed well here.")
    .replace(/\s+/g, " ")
    .trim();

  return sentence
    .replace(/\s+/g, " ")
    .replace(/\.\s+Outstanding work\.$/, ". Outstanding work!")
    .replace(/\.\s+Outstanding job\.$/, ". Outstanding job!");
};

const generateWorkoutSummaryInsightFromGraphData = (graphData: GraphSeries[], blockType?: BlockType): WorkoutSummaryInsight | null => {
  if (!graphData.length || !blockType) return null;

  const scorecard = buildAISummaryScorecard(graphData, blockType);
  if (!scorecard) return null;

  const classification = classifyAISummaryLabel(scorecard);
  const achievements = buildAISummaryAchievements(scorecard, classification);
  const interpretedAchievements = buildAISummaryInterpretedAchievements(scorecard, classification, achievements);
  const keyFactorInterpretations = buildAISummaryInterpretedAchievements(scorecard, classification, achievements, 6);
  const keyFactors = buildAISummaryKeyFactors(scorecard, classification, achievements, keyFactorInterpretations);
  const highlights = buildAISummaryHighlightsFromInterpretations(interpretedAchievements);
  const story = locateAISummaryStory(scorecard, classification);
  const slots = composeAISummarySlots(scorecard, classification, story, achievements, interpretedAchievements, highlights);
  const summary = cleanupAISummaryText(slots);
  const headline = getAISummaryHeadline(classification, story);

  return {
    id: `ai-summary-${blockType}-${classification.label.replace(/\s+/g, "-").toLowerCase()}-${scorecard.sessionCount}-${graphData.map((series) => series.exerciseId).join("-")}`,
    label: classification.label,
    headline,
    summary,
    tone: story.tone,
    reportAccuracy: scorecard.dataConfidence,
    accuracyReason: scorecard.dataConfidence === "High" ? "stable data set" : scorecard.dataConfidence === "Moderate" ? "developing data set" : "limited data",
    achievements,
    interpretedAchievements,
    keyFactors,
    highlights,
    markers: scorecard.markers,
    slots,
  };
};

const getAISummaryToneClasses = (tone: AISummaryTone) => {
  if (tone === "exceptional") return "bg-emerald-100 text-emerald-800 ring-emerald-200";
  if (tone === "positive") return "bg-teal-100 text-teal-800 ring-teal-200";
  if (tone === "contextual") return "bg-amber-100 text-amber-800 ring-amber-200";
  if (tone === "baseline") return "bg-sky-100 text-sky-800 ring-sky-200";
  return "bg-slate-100 text-slate-700 ring-slate-200";
};

function AISummaryMiniCard({ title, detail }: { title: string; detail: string }) {
  return (
    <div className="rounded-xl border border-zinc-100 bg-zinc-50 p-3">
      <div className="text-sm font-semibold text-zinc-900">{title}</div>
      <p className="mt-1 text-xs leading-5 text-zinc-600">{detail}</p>
    </div>
  );
}

function GraphInsightCard({ insight }: { insight: WorkoutSummaryInsight | null }) {
  const [open, setOpen] = useState(false);

  useEffect(() => {
    setOpen(false);
  }, [insight?.id]);

  if (!insight) {
    return (
      <section className="rounded-2xl border border-dashed border-zinc-300 bg-zinc-50 p-4 text-sm text-zinc-500">
        Add more saved sessions to generate a workout summary for this graph.
      </section>
    );
  }

  const toneClasses = getAISummaryToneClasses(insight.tone);
  const visibleKeyFactors = insight.keyFactors.slice(0, 2);
  const expandedKeyFactors = insight.keyFactors.slice(2, 6);
  const secondaryDetails = expandedKeyFactors.length ? expandedKeyFactors : insight.markers.slice(0, 5).map((marker) => ({
    id: `${marker.kind}-${marker.text}`,
    title: marker.kind.replace(/_/g, " "),
    detail: marker.text,
    strength: marker.strength,
    priority: marker.strength * 10,
  }));

  return (
    <section className="rounded-2xl border border-zinc-200 bg-white p-4 shadow-sm">
      <div className="flex items-start gap-3">
        <div className="rounded-2xl bg-zinc-950 px-3 py-2 text-sm font-bold text-white shadow-sm">AI</div>
        <div className="min-w-0 flex-1">
          <div className="flex flex-wrap items-center gap-2">
            <h3 className="text-sm font-bold uppercase tracking-wide text-zinc-700">Workout Summary</h3>
            <span className={`rounded-full px-2.5 py-1 text-xs font-semibold ring-1 ${toneClasses}`}>{insight.label}</span>
            <span className="rounded-full bg-zinc-100 px-2.5 py-1 text-xs font-semibold text-zinc-600">
              Report Accuracy: {insight.reportAccuracy} · {insight.accuracyReason}
            </span>
          </div>

          <p className="mt-2 text-lg font-semibold leading-snug text-zinc-950">{insight.headline}</p>
          <p className="mt-2 text-sm leading-6 text-zinc-700">{insight.summary}</p>


          {visibleKeyFactors.length ? (
            <div className="mt-3">
              <p className="mb-1 text-xs font-bold uppercase tracking-wide text-zinc-500">Key Factors</p>
              <div className="grid gap-2 sm:grid-cols-2">
                {visibleKeyFactors.map((factor) => (
                  <AISummaryMiniCard key={`${insight.id}-${factor.id}`} title={factor.title} detail={factor.detail} />
                ))}
              </div>
            </div>
          ) : null}

          {secondaryDetails.length ? (
            <div className="mt-3">
              <button type="button" onClick={() => setOpen((value) => !value)} className="text-xs font-semibold uppercase tracking-wide text-zinc-500">
                {open ? "Hide Details" : "Show Details"}
              </button>
              {open ? (
                <div className="mt-2 grid gap-2 sm:grid-cols-2">
                  {secondaryDetails.map((factor) => (
                    <AISummaryMiniCard key={`${insight.id}-${factor.id}`} title={factor.title} detail={factor.detail} />
                  ))}
                </div>
              ) : null}
            </div>
          ) : null}
        </div>
      </div>
    </section>
  );
}

function TrackerMetricTooltip({
  active,
  payload,
}: {
  active?: boolean;
  payload?: Array<{ payload?: TrackerMetricGraphPoint }>;
}) {
  if (!active || !payload?.length) return null;

  const point = payload[0]?.payload;
  if (!point) return null;

  return (
    <div className="rounded-xl border border-zinc-200 bg-white px-3 py-2 text-xs shadow-lg">
      <div className="font-semibold text-zinc-900">{point.exerciseName}</div>
      <div className="mt-1 text-zinc-700">{point.contextLabel}</div>
      <div className="mt-1 text-zinc-700">{point.metric}: <span className="font-semibold">{point.rawValue}</span></div>
      {point.weightValue ? <div className="mt-1 text-zinc-700">Weight: <span className="font-semibold">{point.weightValue}</span></div> : null}
      {Object.entries(point.supportValues || {}).map(([metric, value]) => (
        <div key={metric} className="mt-1 text-zinc-700">{metric}: <span className="font-semibold">{value}</span></div>
      ))}
      <div className="mt-1 text-zinc-500">{point.entryDate}</div>
    </div>
  );
}

function TrackerMetricChart({ series }: { series: TrackerMetricGraphSeries }) {
  const yValues = series.points.map((point) => point.y);
  const minY = yValues.length ? Math.min(...yValues) : 0;
  const maxY = yValues.length ? Math.max(...yValues) : 1;
  const padding = Math.max(1, Math.ceil((maxY - minY) * 0.15));
  const domain: [number, number] = [Math.floor(minY - padding), Math.ceil(maxY + padding)];
  const weightValues = Array.from(new Set(series.points.map((point) => point.weightValue).filter(Boolean)));

  if (series.completionOnly) {
    return (
      <div className="rounded-2xl border border-zinc-200 bg-white p-4">
        <div className="text-sm font-bold text-zinc-900">Consistency Check</div>
        <div className="mt-2 rounded-xl border border-dashed border-zinc-300 bg-zinc-50 p-4 text-sm text-zinc-600">
          This exercise has completion/context entries but no measured output yet. Treat it as completed-as-prescribed rather than a performance trend.
        </div>
      </div>
    );
  }

  return (
    <div className="rounded-2xl border border-zinc-200 bg-white p-4">
      <div className="flex items-start justify-between gap-3">
        <div>
          <div className="text-sm font-bold text-zinc-900">{series.metric}</div>
          <div className="mt-0.5 text-xs text-zinc-500">{series.points.length} graphable entr{series.points.length === 1 ? "y" : "ies"}</div>
        </div>
        {series.points[0]?.unitLabel ? <div className="rounded-full bg-zinc-100 px-2 py-1 text-[11px] font-semibold text-zinc-600">{series.points[0].unitLabel}</div> : null}
      </div>

      {series.points.length >= 2 ? (
        <div className="mt-3 h-44 rounded-xl bg-zinc-50 p-2 graph-ui-lock">
          <ResponsiveContainer width="100%" height="100%">
            <LineChart data={series.points} margin={{ top: 10, right: 14, bottom: 10, left: -18 }}>
              <CartesianGrid strokeDasharray="3 3" vertical={false} />
              <XAxis dataKey="xLabel" tick={{ fontSize: 10 }} interval="preserveStartEnd" />
              <YAxis tick={{ fontSize: 10 }} domain={domain} />
              <Tooltip content={<TrackerMetricTooltip />} cursor={false} />
              <Line
                type="monotone"
                dataKey="y"
                stroke="currentColor"
                strokeWidth={2}
                dot={({ cx, cy, payload }: any) => {
                  if (cx == null || cy == null || !payload) return null;
                  const fill = getStableWeightColor(payload.weightValue || "BW");
                  return <circle cx={cx} cy={cy} r={4} fill={fill} stroke={fill} strokeWidth={1.5} />;
                }}
                activeDot={({ cx, cy, payload }: any) => {
                  if (cx == null || cy == null || !payload) return null;
                  const fill = getStableWeightColor(payload.weightValue || "BW");
                  return <circle cx={cx} cy={cy} r={6} fill={fill} stroke={fill} strokeWidth={1.5} />;
                }}
                isAnimationActive={false}
              />
            </LineChart>
          </ResponsiveContainer>
        </div>
      ) : series.points.length === 1 ? (
        <div className="mt-3 rounded-xl border border-dashed border-zinc-300 bg-zinc-50 p-4 text-sm text-zinc-600">
          One graphable entry so far: <span className="font-semibold text-zinc-900">{series.points[0].rawValue}</span>. Add another entry to draw a trend.
        </div>
      ) : (
        <div className="mt-3 rounded-xl border border-dashed border-zinc-300 bg-zinc-50 p-4 text-sm text-zinc-600">
          No measured output detected for this metric yet.
        </div>
      )}

      {weightValues.length ? (
        <div className="mt-3 rounded-xl border border-zinc-100 bg-zinc-50 p-3">
          <div className="mb-2 text-[11px] font-semibold uppercase tracking-wide text-zinc-500">Weight Key</div>
          <div className="flex flex-wrap gap-2">
            {weightValues.map((weight) => (
              <span key={weight} className="inline-flex items-center gap-1 rounded-full bg-white px-2 py-1 text-[11px] font-semibold text-zinc-600">
                <span className="h-2.5 w-2.5 rounded-full" style={{ backgroundColor: getStableWeightColor(weight) }} />
                {weight}
              </span>
            ))}
          </div>
        </div>
      ) : null}

      {series.supportMetrics.length ? (
        <div className="mt-2 text-xs text-zinc-500">Support/context: {series.supportMetrics.join(", ")}</div>
      ) : null}
      {series.skippedValues.length ? (
        <div className="mt-2 text-xs text-zinc-500">
          Preserved non-graphable value{series.skippedValues.length === 1 ? "" : "s"}: {series.skippedValues.map((value) => value.rawValue).join(", ")}
        </div>
      ) : null}
    </div>
  );
}

